const border = { style: BorderStyle.SINGLE, size: 1, color: "999999" };
const borders = { top: border, bottom: border, left: border, right: border };
const cellMargins = { top: 60, bottom: 60, left: 100, right: 100 };

function heading(text, level) {
  return new Paragraph({
    heading: level,
    spacing: { before: level === HeadingLevel.HEADING_1 ? 300 : 200, after: 120 },
    children: [new TextRun({ text, bold: true, font: "Arial", size: level === HeadingLevel.HEADING_1 ? 32 : level === HeadingLevel.HEADING_2 ? 26 : 22 })]
  });
}

function para(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 100 },
    alignment: opts.alignment || AlignmentType.LEFT,
    children: [new TextRun({ text, font: "Arial", size: 21, bold: opts.bold || false, italics: opts.italics || false, color: opts.color || "000000" })]
  });
}

function multiPara(runs) {
  return new Paragraph({
    spacing: { after: 100 },
    children: runs.map(r => new TextRun({ text: r.text, font: "Arial", size: 21, bold: r.bold || false, italics: r.italics || false, color: r.color || "000000" }))
  });
}

function bulletItem(text, ref) {
  return new Paragraph({
    numbering: { reference: ref, level: 0 },
    spacing: { after: 60 },
    children: [new TextRun({ text, font: "Arial", size: 21 })]
  });
}

function bulletItemBold(boldText, normalText, ref) {
  return new Paragraph({
    numbering: { reference: ref, level: 0 },
    spacing: { after: 60 },
    children: [
      new TextRun({ text: boldText, font: "Arial", size: 21, bold: true }),
      new TextRun({ text: normalText, font: "Arial", size: 21 })
    ]
  });
}

function makeCell(text, opts = {}) {
  return new TableCell({
    borders,
    width: { size: opts.width || 2340, type: WidthType.DXA },
    margins: cellMargins,
    shading: opts.shading ? { fill: opts.shading, type: ShadingType.CLEAR } : undefined,
    children: [new Paragraph({ children: [new TextRun({ text, font: "Arial", size: 20, bold: opts.bold || false, color: opts.color || "000000" })] })]
  });
}

